import{_ as o,c as t,o as a,ae as i}from"./chunks/framework.BHrE6nLq.js";const h=JSON.parse('{"title":"How to Set Up Picstome on Your Own Server","description":"","frontmatter":{},"headers":[],"relativePath":"install.md","filePath":"install.md"}'),s={name:"install.md"};function r(n,e,l,p,c,d){return a(),t("div",null,e[0]||(e[0]=[i('<h1 id="how-to-set-up-picstome-on-your-own-server" tabindex="-1">How to Set Up Picstome on Your Own Server <a class="header-anchor" href="#how-to-set-up-picstome-on-your-own-server" aria-label="Permalink to &quot;How to Set Up Picstome on Your Own Server&quot;">ŌĆŗ</a></h1><h2 id="step-1-buy-a-vps-virtual-private-server" tabindex="-1">Step 1: Buy a VPS (Virtual Private Server) <a class="header-anchor" href="#step-1-buy-a-vps-virtual-private-server" aria-label="Permalink to &quot;Step 1: Buy a VPS (Virtual Private Server)&quot;">ŌĆŗ</a></h2><p>To run Picstome, you need a VPS. We recommend Contabo for its balance of price and performance. Alternatively, you can use DigitalOcean, Linode, or any other VPS provider.</p><ol><li>Go to <a href="https://contabo.com/" target="_blank" rel="noreferrer">Contabo</a> or your preferred VPS provider.</li><li>Choose a plan (Cloud VPS 1 with 400 GB SSD better for more storage and really cheap)</li><li>During the setup, select <strong>Ubuntu 24.04</strong> as the operating system.</li></ol><hr><h2 id="step-2-point-your-domain-name-to-your-vps" tabindex="-1">Step 2: Point Your Domain Name to Your VPS <a class="header-anchor" href="#step-2-point-your-domain-name-to-your-vps" aria-label="Permalink to &quot;Step 2: Point Your Domain Name to Your VPS&quot;">ŌĆŗ</a></h2><p>You need to connect your domain (e.g., <code>yourdomain.com</code>) to your VPS&#39;s IP address.</p><ol><li><p><strong>Find Your VPS IP Address</strong>:</p><ul><li>Log in to your VPS providerŌĆÖs dashboard.</li><li>Look for the public IP address of your server (it will look like <code>192.168.X.X</code>).</li><li>Most times will be sent via email with the credentials to access the server.</li></ul></li><li><p><strong>Update Your DNS Settings</strong>:</p><ul><li>Log in to your domain registrar (e.g., GoDaddy, Namecheap, Google Domains).</li><li>Go to the DNS settings for your domain.</li><li>Add an <strong>A record</strong>: <ul><li><strong>Name</strong>: <code>@</code> (for the root domain) or <code>picstome</code> (if using a subdomain like <code>picstome.example.com</code>).</li><li><strong>Value</strong>: Your VPS IP address.</li><li><strong>TTL</strong>: Leave the default or set it to 1 hour.</li></ul></li></ul></li><li><p>Wait for the DNS changes to propagate (this may take a few minutes to a few hours).</p></li></ol><hr><h2 id="step-3-access-your-vps-console" tabindex="-1">Step 3: Access Your VPS Console <a class="header-anchor" href="#step-3-access-your-vps-console" aria-label="Permalink to &quot;Step 3: Access Your VPS Console&quot;">ŌĆŗ</a></h2><p>YouŌĆÖll need to log into your VPS to run the installation script.</p><ol><li><p><strong>Access the Console</strong>:</p><ul><li>If youŌĆÖre using a desktop computer: <ul><li>On <strong>Windows</strong>, open the Command Prompt.</li><li>On <strong>macOS/Linux</strong>, open the Terminal app.</li></ul></li><li>Run the following command to connect to your VPS:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@YOUR_SERVER_IP</span></span></code></pre></div>Replace <code>YOUR_SERVER_IP</code> with your VPS&#39;s public IP address.</li><li>When prompted, enter the password provided by your VPS provider.</li></ul></li><li><p>If this is your first time logging in, you might be asked to change the root password. Follow the instructions to set a new password.</p></li></ol><hr><h2 id="step-4-run-the-picstome-installation-script" tabindex="-1">Step 4: Run the Picstome Installation Script <a class="header-anchor" href="#step-4-run-the-picstome-installation-script" aria-label="Permalink to &quot;Step 4: Run the Picstome Installation Script&quot;">ŌĆŗ</a></h2><p>Once logged into your VPS:</p><ol><li>Run the following command to start the installation:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://picstome.com/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sh</span></span></code></pre></div></li><li>During the installation: <ul><li>YouŌĆÖll be asked to provide the domain name you want to use (e.g., <code>picstome.example.com</code>).</li><li>Ensure that the domain is already pointing to your VPS IP address (Step 2).</li></ul></li></ol><p>The script will:</p><ul><li>Install all necessary software (PHP, Node.js, Nginx, etc.).</li><li>Set up an SSL certificate for secure connections.</li><li>Deploy Picstome and configure it to work with your domain.</li></ul><hr><h2 id="step-5-access-your-picstome-dashboard" tabindex="-1">Step 5: Access Your Picstome Dashboard <a class="header-anchor" href="#step-5-access-your-picstome-dashboard" aria-label="Permalink to &quot;Step 5: Access Your Picstome Dashboard&quot;">ŌĆŗ</a></h2><p>Once the installation is complete:</p><ol><li><p>Open your browser and go to:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://yourdomain.com</span></span></code></pre></div><p>(Replace <code>yourdomain.com</code> with the domain you entered during the installation.)</p></li><li><p>Log in with the default credentials:</p><ul><li><strong>Username</strong>: <code>admin</code></li><li><strong>Password</strong>: <code>password</code></li></ul></li><li><p>For security, change your password immediately:</p><ul><li>Go to the <strong>Settings</strong> page in the dashboard.</li><li>Update your password to something secure.</li></ul></li></ol><hr><h2 id="step-6-ready-to-use" tabindex="-1">Step 6: Ready to Use! <a class="header-anchor" href="#step-6-ready-to-use" aria-label="Permalink to &quot;Step 6: Ready to Use!&quot;">ŌĆŗ</a></h2><p>Your Picstome application is now live! ­¤Äē</p><p>You can start uploading images, managing content, and using the full features of Picstome. If you encounter any issues, check our <a href="https://picstome.com/" target="_blank" rel="noreferrer">documentation</a> or contact support.</p>',26)]))}const m=o(s,[["render",r]]);export{h as __pageData,m as default};
